tests.code:
try:
    read_head('/tmp/does-not-exist.txt')
    assert False, 'Expected FileNotFoundError.'
except FileNotFoundError:
    pass
try:
    read_head('/tmp/does-not-exist.txt', -1)
    assert False, 'Expected ValueError for a negative count.'
except ValueError:
    pass

for value in ['excellent', '3.5', 'Z']:
    try:
        convert_grade(value)
        assert False, 'Expected ValueError.'
    except ValueError:
        pass

try:
    remove_comments('/tmp/no_source.py', '/tmp/no_output.py')
    assert False, 'Expected FileNotFoundError.'
except FileNotFoundError:
    pass

try:
    lookup_element('Unobtainium', [(1, 'H', 'Hydrogen')])
    assert False, 'Expected LookupError.'
except LookupError:
    pass

try:
    most_popular_names('/tmp', 2020, 2019)
    assert False, 'Expected ValueError.'
except ValueError:
    pass
